import 'package:flutter_dotenv/flutter_dotenv.dart';

class EnvConfig {
  static String get awsAccessKey => dotenv.env['AWS_ACCESS_KEY_ID'] ?? '';
  static String get awsSecretKey => dotenv.env['AWS_SECRET_ACCESS_KEY'] ?? '';
  static String get googleApiKey => dotenv.env['GOOGLE_CLOUD_API_KEY'] ?? '';
  static String get s3Bucket => dotenv.env['AWS_S3_BUCKET'] ?? '';
  static String get awsRegion => dotenv.env['AWS_REGION'] ?? 'us-east-1';

  static void validate() {
    final missing = <String>[];
    if (awsAccessKey.isEmpty) missing.add('AWS_ACCESS_KEY_ID');
    if (awsSecretKey.isEmpty) missing.add('AWS_SECRET_ACCESS_KEY');
    if (googleApiKey.isEmpty) missing.add('GOOGLE_CLOUD_API_KEY');
    if (s3Bucket.isEmpty) missing.add('AWS_S3_BUCKET');
    if (missing.isNotEmpty) {
      throw Exception(
        'Missing environment variables: ${missing.join(", ")}\n'
        'Copy .env.example to .env and fill in your credentials.',
      );
    }
  }
}

// lib/services/s3_upload_service.dart
import 'dart:convert';
import 'dart:io';
import 'package:crypto/crypto.dart';
import 'package:http/http.dart' as http;
import 'package:path/path.dart' as path;
import '../config/env_config.dart';

class S3UploadService {
  static Future<String> uploadFile(File file) async {
    final fileName =
        '${DateTime.now().millisecondsSinceEpoch}_${path.basename(file.path)}';
    final bucket = EnvConfig.s3Bucket;
    final region = EnvConfig.awsRegion;
    final accessKey = EnvConfig.awsAccessKey;
    final secretKey = EnvConfig.awsSecretKey;

    final now = DateTime.now().toUtc();
    final dateStamp = _formatDate(now);
    final amzDate = _formatAmzDate(now);
    final host = '$bucket.s3.$region.amazonaws.com';
    final objectKey = 'uploads/$fileName';

    final fileBytes = await file.readAsBytes();
    final payloadHash = sha256.convert(fileBytes).toString();

    final canonicalUri = '/$objectKey';
    final canonicalQueryString = '';
    final contentType = _getContentType(file.path);

    final canonicalHeaders = 'content-type:$contentType\n'
        'host:$host\n'
        'x-amz-content-sha256:$payloadHash\n'
        'x-amz-date:$amzDate\n';

    final signedHeaders = 'content-type;host;x-amz-content-sha256;x-amz-date';

    final canonicalRequest = 'PUT\n'
        '$canonicalUri\n'
        '$canonicalQueryString\n'
        '$canonicalHeaders\n'
        '$signedHeaders\n'
        '$payloadHash';

    final credentialScope = '$dateStamp/$region/s3/aws4_request';
    final stringToSign = 'AWS4-HMAC-SHA256\n'
        '$amzDate\n'
        '$credentialScope\n'
        '${sha256.convert(utf8.encode(canonicalRequest))}';

    final signingKey = _getSignatureKey(secretKey, dateStamp, region, 's3');
    final signature =
        Hmac(sha256, signingKey).convert(utf8.encode(stringToSign)).toString();

    final authorizationHeader = 'AWS4-HMAC-SHA256 '
        'Credential=$accessKey/$credentialScope, '
        'SignedHeaders=$signedHeaders, '
        'Signature=$signature';

    final url = Uri.parse('https://$host$canonicalUri');

    final response = await http.put(
      url,
      headers: {
        'Content-Type': contentType,
        'Host': host,
        'x-amz-content-sha256': payloadHash,
        'x-amz-date': amzDate,
        'Authorization': authorizationHeader,
      },
      body: fileBytes,
    );

    if (response.statusCode == 200 || response.statusCode == 201) {
      return url.toString();
    } else {
      throw Exception(
        'S3 upload failed: ${response.statusCode} - ${response.body}',
      );
    }
  }

  static String _formatDate(DateTime date) {
    return '${date.year}${date.month.toString().padLeft(2, '0')}'
        '${date.day.toString().padLeft(2, '0')}';
  }

  static String _formatAmzDate(DateTime date) {
    return '${_formatDate(date)}T'
        '${date.hour.toString().padLeft(2, '0')}'
        '${date.minute.toString().padLeft(2, '0')}'
        '${date.second.toString().padLeft(2, '0')}Z';
  }

  static List<int> _getSignatureKey(
    String key,
    String dateStamp,
    String region,
    String service,
  ) {
    final kDate =
        Hmac(sha256, utf8.encode('AWS4$key')).convert(utf8.encode(dateStamp));
    final kRegion = Hmac(sha256, kDate.bytes).convert(utf8.encode(region));
    final kService = Hmac(sha256, kRegion.bytes).convert(utf8.encode(service));
    final kSigning =
        Hmac(sha256, kService.bytes).convert(utf8.encode('aws4_request'));
    return kSigning.bytes;
  }

  static String _getContentType(String filePath) {
    final ext = path.extension(filePath).toLowerCase();
    switch (ext) {
      case '.jpg':
      case '.jpeg':
        return 'image/jpeg';
      case '.png':
        return 'image/png';
      case '.gif':
        return 'image/gif';
      case '.webp':
        return 'image/webp';
      default:
        return 'application/octet-stream';
    }
  }
}

