class VisionAnalysisResult {
  final List<LabelResult> labels;
  final List<TextResult> textAnnotations;
  final List<FaceResult> faces;
  final SafeSearchResult? safeSearch;
  final List<LandmarkResult> landmarks;
  final List<LogoResult> logos;

  VisionAnalysisResult({
    required this.labels,
    required this.textAnnotations,
    required this.faces,
    this.safeSearch,
    required this.landmarks,
    required this.logos,
  });

  factory VisionAnalysisResult.fromJson(Map<String, dynamic> json) {
    final response = json['responses']?[0] ?? {};

    return VisionAnalysisResult(
      labels: (response['labelAnnotations'] as List<dynamic>? ?? [])
          .map((e) => LabelResult.fromJson(e))
          .toList(),
      textAnnotations: (response['textAnnotations'] as List<dynamic>? ?? [])
          .map((e) => TextResult.fromJson(e))
          .toList(),
      faces: (response['faceAnnotations'] as List<dynamic>? ?? [])
          .map((e) => FaceResult.fromJson(e))
          .toList(),
      safeSearch: response['safeSearchAnnotation'] != null
          ? SafeSearchResult.fromJson(response['safeSearchAnnotation'])
          : null,
      landmarks: (response['landmarkAnnotations'] as List<dynamic>? ?? [])
          .map((e) => LandmarkResult.fromJson(e))
          .toList(),
      logos: (response['logoAnnotations'] as List<dynamic>? ?? [])
          .map((e) => LogoResult.fromJson(e))
          .toList(),
    );
  }

  bool get isEmpty =>
      labels.isEmpty &&
      textAnnotations.isEmpty &&
      faces.isEmpty &&
      landmarks.isEmpty &&
      logos.isEmpty;
}

