class VisionService {
  static const String _baseUrl =
      'https://vision.googleapis.com/v1/images:annotate';

  static Future<VisionAnalysisResult> analyzeImage(File imageFile) async {
    final apiKey = EnvConfig.googleApiKey;
    final bytes = await imageFile.readAsBytes();
    final base64Image = base64Encode(bytes);

    final requestBody = {
      'requests': [
        {
          'image': {'content': base64Image},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 15},
            {'type': 'TEXT_DETECTION', 'maxResults': 10},
            {'type': 'FACE_DETECTION', 'maxResults': 10},
            {'type': 'SAFE_SEARCH_DETECTION'},
            {'type': 'LANDMARK_DETECTION', 'maxResults': 5},
            {'type': 'LOGO_DETECTION', 'maxResults': 5},
          ],
        }
      ],
    };

    final response = await http.post(
      Uri.parse('$_baseUrl?key=$apiKey'),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(requestBody),
    );

    if (response.statusCode == 200) {
      final json = jsonDecode(response.body);
      if (json['responses']?[0]?['error'] != null) {
        throw Exception(json['responses'][0]['error']['message']);
      }
      return VisionAnalysisResult.fromJson(json);
    } else {
      final error = jsonDecode(response.body);
      throw Exception(
        'Vision API error: ${error['error']?['message'] ?? response.body}',
      );
    }
  }
}

